index 048286d7a97b..36df3792200d 100644
--- a/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
@@ -3806,7 +3806,14 @@ void VPFirstOrderRecurrencePHIRecipe::execute(VPTransformState &State) {
   // Create a phi node for the new recurrence.
   PHINode *Phi = PHINode::Create(VecTy, 2, "vector.recur");
   Phi->insertBefore(State.CFG.PrevBB->getFirstInsertionPt());
+  // Incoming from the preheader (vector.ph): the initial value.
   Phi->addIncoming(VectorInit, VectorPH);
+  // Add a placeholder incoming for the backedge from the vector loop header.
+  // This ensures the PHI is well-formed with two incoming edges and avoids
+  // creating a use that does not dominate. The actual backedge value will be
+  // spliced/updated later during VPlan transforms (e.g. fixed-order recurrence
+  // adjustment). Using undef here is safe and gets replaced before final codegen.
+  Phi->addIncoming(UndefValue::get(VecTy), State.CFG.PrevBB);
   State.set(this, Phi);
 }

