   // Create a phi node for the new recurrence.
   PHINode *Phi = PHINode::Create(VecTy, 2, "vector.recur");
   Phi->insertBefore(State.CFG.PrevBB->getFirstInsertionPt());
+  // Add incoming from preheader and also from the header backedge with the same
+  // initial value for degenerate recurrences where the backedge simplifies to
+  // the start value. Using the preheader-defined value as the backedge incoming
+  // is valid (it dominates the header) and prevents creating a non-dominating
+  // broadcast in the header.
   Phi->addIncoming(VectorInit, VectorPH);
+  Phi->addIncoming(VectorInit, State.CFG.PrevBB);
   State.set(this, Phi);
 }

