   Phi->insertBefore(State.CFG.PrevBB->getFirstInsertionPt());
+  // Add incoming from preheader and a placeholder backedge incoming from the
+  // latch block to make the PHI structurally valid. The actual backedge value
+  // will be set up later during VPlan transforms.
   Phi->addIncoming(VectorInit, VectorPH);
+  // Determine the latch IR block corresponding to the header's successor in the
