index 048286d7a97b..acd8ae68265f 100644
--- a/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
@@ -3806,7 +3806,15 @@ void VPFirstOrderRecurrencePHIRecipe::execute(VPTransformState &State) {
   // Create a phi node for the new recurrence.
   PHINode *Phi = PHINode::Create(VecTy, 2, "vector.recur");
   Phi->insertBefore(State.CFG.PrevBB->getFirstInsertionPt());
+  // Incoming from the preheader (vector.ph): the initial value.
   Phi->addIncoming(VectorInit, VectorPH);
+  // Add a placeholder incoming from the latch (vector.body). The actual value
+  // will be set up later during VPlan transforms.
+  auto *HeaderVPBB = getParent();
+  assert(HeaderVPBB->getNumSuccessors() == 1 && "header should have one successor inside region");
+  auto *LatchVPBB = cast<VPBasicBlock>(HeaderVPBB->getSuccessors()[0]);
+  BasicBlock *VectorLatchIR = State.CFG.VPBB2IRBB.at(LatchVPBB);
+  Phi->addIncoming(UndefValue::get(VecTy), VectorLatchIR);
   State.set(this, Phi);
 }

